data.output:
	statusMap := make(map[string]string)
	childCount := make(map[string]int)
	openChildCount := make(map[string]int)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
		if b.Parent != "" {
			childCount[b.Parent]++
			if b.Status != StatusClosed {
				openChildCount[b.Parent]++
			}
		}
	}
	now := time.Now().UTC()
	var soonestRetry time.Time
	for _, b := range beads {
		if !depsSatisfied(b, statusMap) {
			continue
		}
		switch b.Status {
		case StatusBlocked, StatusProposed, StatusCancelled:
			out.SkippedBlocked = append(out.SkippedBlocked, b.ID)
			continue
		case StatusInProgress:
			if !claimLeaseIsStale(s, b.Extra, b.ID) {
				continue
			}
		case StatusOpen:
		default:
			continue
		}
		if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
			if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
				if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
					out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
					if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
						soonestRetry = retryAfter
					}
					continue
				}
			}
		}
		if isOrdinaryEpicContainer(b, childCount[b.ID]) {
			if isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]) {
				out.SkippedEpicClosureCandidates = append(out.SkippedEpicClosureCandidates, b.ID)
			} else {
				out.SkippedEpics = append(out.SkippedEpics, b.ID)
			}
			continue
		}
		if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
			out.SkippedNeedsInvestigation = append(out.SkippedNeedsInvestigation, b.ID)
			continue
		}
		if eligible, ok := b.Extra["execution-eligible"]; ok {
			if val, isBool := eligible.(bool); isBool && !val {
				out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
				continue
			}
		}
		if sup, ok := b.Extra["superseded-by"]; ok {
			if s, isStr := sup.(string); isStr && s != "" {
				out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
				continue
			}
		}
	}
	if !soonestRetry.IsZero() {
		out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
	}
	return out, nil
}

func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
	beads, err := s.ReadAll()
	if err != nil {
		return nil, err
	}
	statusMap := make(map[string]string)
	childCount := make(map[string]int)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
		if b.Parent != "" {
			childCount[b.Parent]++
		}
	}

	var ready []Bead
	for _, b := range beads {
		if b.Status != StatusOpen {
			// Surface stalled in_progress beads so a fresh worker can
			// reclaim them atomically in Claim().
			if executionOnly && b.Status == StatusInProgress && claimLeaseIsStale(s, b.Extra, b.ID) {
				// fall through to dependency check below
			} else {
				continue
			}
		}
		allSatisfied := true
		for _, depID := range b.DepIDs() {
			if statusMap[depID] != StatusClosed {
				allSatisfied = false
				break
			}
		}
		if !allSatisfied {
			continue
		}
		if executionOnly {
			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
				continue
			}
			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
				continue
			}
			// Filter by execution-eligible (default true if absent)
			eligible, ok := b.Extra["execution-eligible"]
			if ok {
				if val, isBool := eligible.(bool); isBool && !val {
					continue
				}
			}
			// Filter out superseded beads
			if sup, ok := b.Extra["superseded-by"]; ok {
				if s, isStr := sup.(string); isStr && s != "" {
					continue
				}
			}
			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
						continue
					}
				}
			}
		}
		ready = append(ready, b)

		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
		if err != nil || !retryAfter.After(now) {
			continue
		}
		blocker := Blocker{
			Kind:           BlockerKindRetryCooldown,
			NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
		}
		if v, ok := b.Extra["execute-loop-last-status"]; ok {
			if s, ok := v.(string); ok {
				blocker.LastStatus = s
			}
		}
		if v, ok := b.Extra["execute-loop-last-detail"]; ok {
			if s, ok := v.(string); ok {
				blocker.LastDetail = s
			}
		}
		entries = append(entries, BlockedBead{
			Bead:    b,
			Blocker: blocker,
		})
	}

	sort.SliceStable(entries, func(i, j int) bool {
		if entries[i].Priority != entries[j].Priority {
			return entries[i].Priority < entries[j].Priority
		}
		if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
			return entries[i].CreatedAt.Before(entries[j].CreatedAt)
		}
		return entries[i].ID < entries[j].ID
	})
	return entries, nil
}

func depsSatisfied(b Bead, statusMap map[string]string) bool {
	for _, depID := range b.DepIDs() {
		if statusMap[depID] != StatusClosed {
			return false
		}
	}
	return true
}

func isOrdinaryEpicContainer(b Bead, childCount int) bool {
	issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
	title := strings.ToLower(strings.TrimSpace(b.Title))
	return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
}

func isEpicClosureCandidate(b Bead, childCount, openChildCount int) bool {
	if childCount == 0 {
		return false
	}
	return isOrdinaryEpicContainer(b, childCount) && openChildCount == 0
}

func sortBeadsForQueue(beads []Bead) {
	sort.SliceStable(beads, func(i, j int) bool {
		if beads[i].Priority != beads[j].Priority {
			return beads[i].Priority < beads[j].Priority
		}
		ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
		jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
		if iok != jok {
			return iok
		}
		if iok && jok && ir != jr {
			return ir < jr
		}
		if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
			return beads[i].CreatedAt.Before(beads[j].CreatedAt)
		}
		return beads[i].ID < beads[j].ID
	})

		parts = append(parts, fmt.Sprintf("speed=%.1f tok/s", attempt.PredictedSpeedTPS))
	}
	if attempt.PredictedCostUSDPer1kTokens > 0 {
		cost := fmt.Sprintf("cost=$%.6f/1k tok", attempt.PredictedCostUSDPer1kTokens)
		if attempt.PredictedCostSource != "" {
			cost += " source=" + attempt.PredictedCostSource
		}
		parts = append(parts, cost)
	} else if attempt.PredictedCostSource != "" {
		parts = append(parts, "cost_source="+attempt.PredictedCostSource)
	}
	return strings.Join(parts, " ")
}

func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
	if asJSON {
		payload := struct {
			ProjectRoot string `json:"project_root"`
			*agent.ExecuteBeadLoopResult
		}{
			ProjectRoot:           projectRoot,
			ExecuteBeadLoopResult: result,
		}
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(payload)
	}

	if result.NoReadyWork {
		fmt.Fprintf(w, "project: %s\n", projectRoot)
		fmt.Fprintln(w, "No execution-ready beads.")
		d := result.NoReadyWorkDetail
		if len(d.SkippedEpics) > 0 {
			fmt.Fprintf(w, "  skipped %d ready epic(s) with open children (epics are structural containers; decompose into tasks): %s\n",
				len(d.SkippedEpics), strings.Join(d.SkippedEpics, ", "))
		}
		if len(d.SkippedEpicClosureCandidates) > 0 {
			fmt.Fprintf(w, "  completed epic closure candidate(s) (all direct children closed; surfaced for closure evaluation): %s\n",
				strings.Join(d.SkippedEpicClosureCandidates, ", "))
		}
		if len(d.SkippedOnCooldown) > 0 {
			retryHint := ""
			if d.NextRetryAfter != "" {
				retryHint = " (next retry-after: " + d.NextRetryAfter + ")"
			}
			fmt.Fprintf(w, "  skipped %d bead(s) on retry cooldown%s: %s\n",
				len(d.SkippedOnCooldown), retryHint, strings.Join(d.SkippedOnCooldown, ", "))
		}
		if len(d.SkippedNeedsInvestigation) > 0 {
			fmt.Fprintf(w, "  skipped %d bead(s) needing investigation or human input: %s\n",
				len(d.SkippedNeedsInvestigation), strings.Join(d.SkippedNeedsInvestigation, ", "))
		}
		if len(d.SkippedBlocked) > 0 {
			fmt.Fprintf(w, "  skipped %d bead(s) with blocked/proposed/cancelled lifecycle status: %s\n",
				len(d.SkippedBlocked), strings.Join(d.SkippedBlocked, ", "))
		}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("unexpected execution for %s", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.True(t, result.NoReadyWork)
	assert.Equal(t, 0, result.Attempts)
}

// TestExecuteBeadWorkerEpicIsNotOrdinaryWork: ordinary ddx work skips epic
// containers unless a dedicated epic-worker path owns them.
func TestExecuteBeadWorkerEpicIsNotOrdinaryWork(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	epic := &bead.Bead{ID: "ddx-epic-001", Title: "Epic container", IssueType: "epic", Priority: 1}
	require.NoError(t, store.Create(epic))

	cooldownTask := &bead.Bead{ID: "ddx-task-002", Title: "Cooldown task", IssueType: "task", Priority: 1,
		Extra: map[string]any{
			"execute-loop-retry-after": time.Now().Add(1 * time.Hour).UTC().Format(time.RFC3339),
		},
	}
	require.NoError(t, store.Create(cooldownTask))

	var executed []string
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			executed = append(executed, beadID)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				Detail:    "epic closed after children",
				SessionID: "sess-" + beadID,
				ResultRev: "deadbeef",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.True(t, result.NoReadyWork, "ordinary ddx work must skip epic containers")
	assert.Empty(t, executed, "ordinary ddx work must not execute epics")
	assert.Equal(t, []string{"ddx-epic-001"}, result.NoReadyWorkDetail.SkippedEpics)
	assert.Equal(t, []string{"ddx-task-002"}, result.NoReadyWorkDetail.SkippedOnCooldown)
}

func TestExecuteBeadWorkerEvaluatesCompletedEpicForClosure(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	completedEpic := &bead.Bead{ID: "ddx-epic-closed", Title: "Completed epic", IssueType: "epic", Priority: 0}
	activeEpic := &bead.Bead{ID: "ddx-epic-open", Title: "Active epic", IssueType: "epic", Priority: 1}
	closedChild := &bead.Bead{ID: "ddx-epic-closed-child", Title: "Closed child", Parent: completedEpic.ID, Status: bead.StatusClosed}
	openChild := &bead.Bead{ID: "ddx-epic-open-child", Title: "Open child", Parent: activeEpic.ID, Status: bead.StatusBlocked}
	require.NoError(t, store.Create(completedEpic))
	require.NoError(t, store.Create(activeEpic))
	require.NoError(t, store.Create(closedChild))
	require.NoError(t, store.Create(openChild))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("unexpected execution for %s", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.True(t, result.NoReadyWork)
	assert.Empty(t, result.Results)
	assert.Equal(t, []string{"ddx-epic-open"}, result.NoReadyWorkDetail.SkippedEpics)
	assert.Equal(t, []string{"ddx-epic-closed"}, result.NoReadyWorkDetail.SkippedEpicClosureCandidates)
}

func TestExecuteBeadWorkerConcurrentWorkersDoNotDoubleExecuteSameBead(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	only := &bead.Bead{ID: "ddx-race-1", Title: "Only ready bead", Priority: 0}
	require.NoError(t, store.Create(only))

	var execCalls atomic.Int32
	started := make(chan struct{}, 1)
	release := make(chan struct{})
	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		execCalls.Add(1)
		select {
		case started <- struct{}{}:
		default:
		}
		<-release
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			Detail:    "merged cleanly",
			SessionID: "sess-race",
			ResultRev: "deadbeef",
		}, nil
	})

	workerA := &ExecuteBeadWorker{Store: store, Executor: executor}
	workerB := &ExecuteBeadWorker{Store: store, Executor: executor}

	var wg sync.WaitGroup
	wg.Add(2)
	results := make([]*ExecuteBeadLoopResult, 2)
	errs := make([]error, 2)

	cfgOptsA := config.TestLoopConfigOpts{Assignee: "worker-a"}
	rcfgA := config.NewTestConfigForLoop(cfgOptsA).Resolve(config.TestLoopOverrides(cfgOptsA))
	cfgOptsB := config.TestLoopConfigOpts{Assignee: "worker-b"}
	rcfgB := config.NewTestConfigForLoop(cfgOptsB).Resolve(config.TestLoopOverrides(cfgOptsB))
	go func() {
		defer wg.Done()
		results[0], errs[0] = workerA.Run(context.Background(), rcfgA, ExecuteBeadLoopRuntime{Once: true})
	}()
	go func() {
		defer wg.Done()
		results[1], errs[1] = workerB.Run(context.Background(), rcfgB, ExecuteBeadLoopRuntime{Once: true})
	}()

	<-started
	close(release)

package cmd

import (
